SELECT priority_level, COUNT(*) AS activity_count
FROM priorities
GROUP BY priority_level;

SELECT prop_type_name, usage_frequency
FROM prop_types
WHERE usage_frequency >= 1;

SELECT user_id, COUNT(change_id) AS number_of_changes
FROM change_history
GROUP BY user_id;

SELECT schedule_key_name
FROM schedule_keys
WHERE schedule_key_id = 1;

SELECT COUNT(DISTINCT activity_id) AS unique_activities
FROM schedules
WHERE character_id = 0;

SELECT change_type, change_date
FROM change_history
ORDER BY change_date DESC;

SELECT priority_level
FROM priorities
WHERE priority_id = 1;
